var surah019 = {
  number: 19,
  nameArabic: "Maryam",
  nameEnglish: "Maryam",
  meaning: "Mary",
  totalAyahs: 98,
  ayahs: [
    { number: 1, arabic: "كٓهيعٓصٓ", transliteration: "KafhayaAAaynsad", transliterationB: "Kaaaf-Haa-Yaa-'Ayyyn-Saaad", english: "Kaf. Ha. Ya. 'Ain. Sad", romanUrdu: "Kaaf , Haa , yaa, ain , saad" },
    { number: 2, arabic: "ذِكْرُ رَحْمَتِ رَبِّكَ عَبْدَهُۥ زَكَرِيَّآ", transliteration: "Thikru rahmati rabbika AAabdahu zakariyya", transliterationB: "Zikru rahmati Rabbika 'abdahoo Zakariyya", english: "(This is) a recital of the Mercy of thy Lord to His servant Zakariya", romanUrdu: "Zikr hai us rehmat ka jo tere Rubb ne apne banday zakariya par ki thi" },
    { number: 3, arabic: "إِذْ نَادَىٰ رَبَّهُۥ نِدَآءً خَفِيًّۭا", transliteration: "Ith nada rabbahu nidaan khafiyyan", transliterationB: "Iz naadaa Rabbahoo nidaaa'an khafiyyaa", english: "Behold! he cried to his Lord in secret", romanUrdu: "Jabke usne apne Rubb ko chupke chupke pukara" },
    { number: 4, arabic: "قَالَ رَبِّ إِنِّى وَهَنَ ٱلْعَظْمُ مِنِّى وَٱشْتَعَلَ ٱلرَّأْسُ شَيْبًۭا وَلَمْ أَكُنۢ بِدُعَآئِكَ رَبِّ شَقِيًّۭا", transliteration: "Qala rabbi innee wahana alAAathmu minnee waishtaAAala alrrasu shayban walam akun biduAAaika rabbi shaqiyyan", transliterationB: "Qaala Rabbi innee wahanal'azmu minnee washta'alar raasu shaibanw wa lam akum bidu'aaa'ika Rabbi shaqiyyaa", english: "Praying: \"O my Lord! infirm indeed are my bones, and the hair of my head doth glisten with grey: but never am I unblest, O my Lord, in my prayer to Thee", romanUrdu: "Usne arz kiya “aey parwardigar, meri haddiyan tak ghul gayi hain aur sar budhape se bhadak utha hai, aey parwardigar, main kabhi tujhse dua maang kar na-murad nahin raha" },
    { number: 5, arabic: "وَإِنِّى خِفْتُ ٱلْمَوَٰلِىَ مِن وَرَآءِى وَكَانَتِ ٱمْرَأَتِى عَاقِرًۭا فَهَبْ لِى مِن لَّدُنكَ وَلِيًّۭا", transliteration: "Wainnee khiftu almawaliya min waraee wakanati imraatee AAaqiran fahab lee min ladunka waliyyan", transliterationB: "Wa innee khiftul mawaa liya minw waraaa'ee wa kaana tim ra atee 'aairan fahab lee mil ladunka waliyyaa", english: "Now I fear (what) my relatives (and colleagues) (will do) after me: but my wife is barren: so give me an heir as from Thyself", romanUrdu: "Mujhey apne peechey apne bhai bandon ki buraiyon ka khauf hai, aur meri biwi baanjh (barren) hai, tu mujhey apne fazal e khaas se ek waris ata karde" },
    { number: 6, arabic: "يَرِثُنِى وَيَرِثُ مِنْ ءَالِ يَعْقُوبَ ۖ وَٱجْعَلْهُ رَبِّ رَضِيًّۭا", transliteration: "Yarithunee wayarithu min ali yaAAqooba waijAAalhu rabbi radiyyan", transliterationB: "Yarisunee wa yarisu min aali Ya'qoob, waj'alhu Rabbi radiyya", english: "(One that) will (truly) represent me, and represent the posterity of Jacob; and make him, O my Lord! one with whom Thou art well-pleased", romanUrdu: "Jo mera bhi ho aur aale yaqub ki miras bhi paye, aur aey parwardigar , usko ek pasandeeda Insaan bana”" },
    { number: 7, arabic: "يَٰزَكَرِيَّآ إِنَّا نُبَشِّرُكَ بِغُلَٰمٍ ٱسْمُهُۥ يَحْيَىٰ لَمْ نَجْعَل لَّهُۥ مِن قَبْلُ سَمِيًّۭا", transliteration: "Ya zakariyya inna nubashshiruka bighulamin ismuhu yahya lam najAAal lahu min qablu samiyyan", transliterationB: "Yaa Zakariyyaaa innaa nubashshiruka bighulaami nismuhoo Yahyaa lam naj'al lahoo min qablu samiyyaa", english: "(His prayer was answered): \"O Zakariya! We give thee good news of a son: His name shall be Yahya: on none by that name have We conferred distinction before", romanUrdu: "(Jawab diya gaya) “Aey zakariya, hum tujhe ek ladke ki basharat dete hain jiska naam Yahya hoga, humne is naam ka koi aadmi issey pehle paida nahin kiya”" },
    { number: 8, arabic: "قَالَ رَبِّ أَنَّىٰ يَكُونُ لِى غُلَٰمٌۭ وَكَانَتِ ٱمْرَأَتِى عَاقِرًۭا وَقَدْ بَلَغْتُ مِنَ ٱلْكِبَرِ عِتِيًّۭا", transliteration: "Qala rabbi anna yakoonu lee ghulamun wakanati imraatee AAaqiran waqad balaghtu mina alkibari AAitiyyan", transliterationB: "Qaala Rabbi annaa yakoonu lee ghulaamunw wa kaanatim ra atee aaqiranw wa qad balaghtu minal kibari 'itiyyaa", english: "He said: \"O my Lord! How shall I have a son, when my wife is barren and I have grown quite decrepit from old age", romanUrdu: "Arz kiya, “parwardigar, bhala mere haan kaise beta hoga jabke meri biwi baanjh (barren) hai aur main boodha hokar sookh chuka hoon?”" },
    { number: 9, arabic: "قَالَ كَذَٰلِكَ قَالَ رَبُّكَ هُوَ عَلَىَّ هَيِّنٌۭ وَقَدْ خَلَقْتُكَ مِن قَبْلُ وَلَمْ تَكُ شَيْـًۭٔا", transliteration: "Qala kathalika qala rabbuka huwa AAalayya hayyinun waqad khalaqtuka min qablu walam taku shayan", transliterationB: "Qaala kazaalika qaala Rabbuka huwa 'alaiya haiyinunw wa qad khalaqtuka min qablu wa lam taku shai'aa", english: "He said: \"So (it will be) thy Lord saith, 'that is easy for Me: I did indeed create thee before, when thou hadst been nothing", romanUrdu: "Jawab mila “aisa hi hoga. Tera Rubb farmata hai ke yeh to mere liye ek zara si baat hai, aakhir issey pehle main tujhey paida kar chuka hoon jabke tu koi cheez na tha”" },
    { number: 10, arabic: "قَالَ رَبِّ ٱجْعَل لِّىٓ ءَايَةًۭ ۚ قَالَ ءَايَتُكَ أَلَّا تُكَلِّمَ ٱلنَّاسَ ثَلَٰثَ لَيَالٍۢ سَوِيًّۭا", transliteration: "Qala rabbi ijAAal lee ayatan qala ayatuka alla tukallima alnnasa thalatha layalin sawiyyan", transliterationB: "Qaala Rabbij 'al leee Aayah; qaala Aayatuka allaa tukalliman naasa salaasa layaalin sawiyyaa", english: "(Zakariya) said: \"O my Lord! give me a Sign.\" \"Thy Sign,\" was the answer, \"Shall be that thou shalt speak to no man for three nights, although thou art not dumb", romanUrdu: "Zakariya ne kaha, “parwardigar, mere liye koi nishani muqarrar karde”. Farmaya “tere liye nishani yeh hai ke tu paiham teen din logon se baat na kar sakey”" },
    { number: 11, arabic: "فَخَرَجَ عَلَىٰ قَوْمِهِۦ مِنَ ٱلْمِحْرَابِ فَأَوْحَىٰٓ إِلَيْهِمْ أَن سَبِّحُوا۟ بُكْرَةًۭ وَعَشِيًّۭا", transliteration: "Fakharaja AAala qawmihi mina almihrabi faawha ilayhim an sabbihoo bukratan waAAashiyyan", transliterationB: "Fakharaja 'alaa qawmihee minal mihraabi fa-awhaaa ilaihim an sabbihoo bukratanw wa 'ashiyyaa", english: "So Zakariya came out to his people from him chamber: He told them by signs to celebrate Allah's praises in the morning and in the evening", romanUrdu: "Chunachey woh mehrab se nikal kar apni qaum ke saamne aaya aur usne isharey se unko hidayat ki ke subh-o-shaam tasbeeh karo" },
    { number: 12, arabic: "يَٰيَحْيَىٰ خُذِ ٱلْكِتَٰبَ بِقُوَّةٍۢ ۖ وَءَاتَيْنَٰهُ ٱلْحُكْمَ صَبِيًّۭا", transliteration: "Ya yahya khuthi alkitaba biquwwatin waataynahu alhukma sabiyyan", transliterationB: "Yaa Yahyaa khuzil Kitaaba biquwwatinw wa aatainaahul hukma saiyyaa", english: "(To his son came the command): \"O Yahya! take hold of the Book with might\": and We gave him Wisdom even as a youth", romanUrdu: "Aey Yahya! Kitab e ilahi ko mazboot thaam le, humne usey bachpan hi mein “hukum” se nawaza" },
    { number: 13, arabic: "وَحَنَانًۭا مِّن لَّدُنَّا وَزَكَوٰةًۭ ۖ وَكَانَ تَقِيًّۭا", transliteration: "Wahananan min ladunna wazakatan wakana taqiyyan", transliterationB: "Wa hanaanam mil ladunnaa wa zakaatanw wa kaana taqiyyaa", english: "And piety (for all creatures) as from Us, and purity: He was devout", romanUrdu: "Aur apni taraf se usko narm dili aur paakeezgi ata ki aur woh bada parheizgaar" },
    { number: 14, arabic: "وَبَرًّۢا بِوَٰلِدَيْهِ وَلَمْ يَكُن جَبَّارًا عَصِيًّۭا", transliteration: "Wabarran biwalidayhi walam yakun jabbaran AAasiyyan", transliterationB: "Wa barram biwaalidayhi wa lam yakum jabbaaran 'asiyyaa", english: "And kind to his parents, and he was not overbearing or rebellious", romanUrdu: "Aur apne walidain ka haqq shanaas (dutiful ) tha, woh jabbar(arrogant) na tha aur na nafarman" },
    { number: 15, arabic: "وَسَلَٰمٌ عَلَيْهِ يَوْمَ وُلِدَ وَيَوْمَ يَمُوتُ وَيَوْمَ يُبْعَثُ حَيًّۭا", transliteration: "Wasalamun AAalayhi yawma wulida wayawma yamootu wayawma yubAAathu hayyan", transliterationB: "Wa salaamun 'alaihi yawma wulida wa yawma yamootu wa yawma yub'asu haiyaa", english: "So Peace on him the day he was born, the day that he dies, and the day that he will be raised up to life (again)", romanUrdu: "Salaam uspar jis roz ke woh paida hua aur jis din marey aur jis roz woh zinda karke uthaya jaye" },
    { number: 16, arabic: "وَٱذْكُرْ فِى ٱلْكِتَٰبِ مَرْيَمَ إِذِ ٱنتَبَذَتْ مِنْ أَهْلِهَا مَكَانًۭا شَرْقِيًّۭا", transliteration: "Waothkur fee alkitabi maryama ithi intabathat min ahliha makanan sharqiyyan", transliterationB: "Wazkur fil Kitaabi Marya; izin tabazat min ahlihaa makaanan shariqyyaa", english: "Relate in the Book (the story of) Mary, when she withdrew from her family to a place in the East", romanUrdu: "Aur (aey Muhammad), is kitaab mein Maryam ka haal bayan karo, jabke woh apne logon se alag ho kar sharqi (eastern side) janib gosha nasheen (in seclusion) ho gayi thi" },
    { number: 17, arabic: "فَٱتَّخَذَتْ مِن دُونِهِمْ حِجَابًۭا فَأَرْسَلْنَآ إِلَيْهَا رُوحَنَا فَتَمَثَّلَ لَهَا بَشَرًۭا سَوِيًّۭا", transliteration: "Faittakhathat min doonihim hijaban faarsalna ilayha roohana fatamaththala laha basharan sawiyyan", transliterationB: "Fattakhazat min doonihim hijaaban fa arsalnaaa ilaihaa roohanaa fatamassala lahaa basharan sawiyyaa", english: "She placed a screen (to screen herself) from them; then We sent her our angel, and he appeared before her as a man in all respects", romanUrdu: "Aur purda daal kar unse chup (hidden) baithi thi is halat mein humne uske paas apni rooh ko (yani farishte ko) bheja aur woh uske saamne ek puray Insan ki shakal mein namudar ho gaya" },
    { number: 18, arabic: "قَالَتْ إِنِّىٓ أَعُوذُ بِٱلرَّحْمَٰنِ مِنكَ إِن كُنتَ تَقِيًّۭا", transliteration: "Qalat innee aAAoothu bialrrahmani minka in kunta taqiyyan", transliterationB: "Qaalat inneee a'oozu bir Rahmaani minka in kunta taqiyyaa", english: "She said: \"I seek refuge from thee to (Allah) Most Gracious: (come not near) if thou dost fear Allah", romanUrdu: "Maryam yakayak bol uthi ke “agar tu koi khuda tars aadmi hai to main tujhse rehman ki panaah maangti hoon”" },
    { number: 19, arabic: "قَالَ إِنَّمَآ أَنَا۠ رَسُولُ رَبِّكِ لِأَهَبَ لَكِ غُلَٰمًۭا زَكِيًّۭا", transliteration: "Qala innama ana rasoolu rabbiki liahaba laki ghulaman zakiyyan", transliterationB: "Qaala innamaa ana rasoolu Rabbiki li ahaba laki ghulaaman zakiyyaa", english: "He said: \"Nay, I am only a messenger from thy Lord, (to announce) to thee the gift of a holy son", romanUrdu: "Usne kaha “main to tere Rubb ka faristada hoon aur isliye bheja gaya hoon ke tujhey ek paakeeza ladka doon”" },
    { number: 20, arabic: "قَالَتْ أَنَّىٰ يَكُونُ لِى غُلَٰمٌۭ وَلَمْ يَمْسَسْنِى بَشَرٌۭ وَلَمْ أَكُ بَغِيًّۭا", transliteration: "Qalat anna yakoonu lee ghulamun walam yamsasnee basharun walam aku baghiyyan", transliterationB: "Qaalat anna yakoonu lee ghulaamunw wa lam yamsasnee bashrunw wa lam aku baghiyyaa", english: "She said: \"How shall I have a son, seeing that no man has touched me, and I am not unchaste", romanUrdu: "Maryam ne kaha “ mere haan kaise ladka hoga jabke mujhey kisi bashar (Insaan) ne chua tak nahin hai aur main koi badhkaar aurat nahin hoon”" },
    { number: 21, arabic: "قَالَ كَذَٰلِكِ قَالَ رَبُّكِ هُوَ عَلَىَّ هَيِّنٌۭ ۖ وَلِنَجْعَلَهُۥٓ ءَايَةًۭ لِّلنَّاسِ وَرَحْمَةًۭ مِّنَّا ۚ وَكَانَ أَمْرًۭا مَّقْضِيًّۭا", transliteration: "Qala kathaliki qala rabbuki huwa AAalayya hayyinun walinajAAalahu ayatan lilnnasi warahmatan minna wakana amran maqdiyyan", transliterationB: "Qaala kazaaliki qaala Rabbuki huwa 'alaiya yaiyimunw wa linaj 'alahooo Aayatal linnaasi wa rahmatam minnaa; wa kaana amram maqdiyyaa", english: "He said: \"So (it will be): Thy Lord saith, 'that is easy for Me: and (We wish) to appoint him as a Sign unto men and a Mercy from Us': It is a matter (so) decreed", romanUrdu: "Farishte ne kaha “ aisa hi hoga, tera Rubb farmata hai ke aisa karna mere liye bahut aasaan hai aur hum yeh isliye karenge ke us ladke ko logon ke liye ek nishani banayein aur apni taraf se ek rehmat, aur yeh kaam hokar rehna hai”" },
    { number: 22, arabic: "۞ فَحَمَلَتْهُ فَٱنتَبَذَتْ بِهِۦ مَكَانًۭا قَصِيًّۭا", transliteration: "Fahamalathu faintabathat bihi makanan qasiyyan", transliterationB: "Fahamalat hu fantabazat bihee makaanan qasiyyaa", english: "So she conceived him, and she retired with him to a remote place", romanUrdu: "Mayam ko us bacchey ka hamal reh gaya aur woh is hamal ko liye huey ek door ke maqaam par chali gayi" },
    { number: 23, arabic: "فَأَجَآءَهَا ٱلْمَخَاضُ إِلَىٰ جِذْعِ ٱلنَّخْلَةِ قَالَتْ يَٰلَيْتَنِى مِتُّ قَبْلَ هَٰذَا وَكُنتُ نَسْيًۭا مَّنسِيًّۭا", transliteration: "Faajaaha almakhadu ila jithAAi alnnakhlati qalat ya laytanee mittu qabla hatha wakuntu nasyan mansiyyan", transliterationB: "Fa ajaaa 'ahal makhaadu ilaa jiz'in nakhlati qaalat yaa laitanee mittu qabla haazaa wa kuntu nasyam mansiyyaa", english: "And the pains of childbirth drove her to the trunk of a palm-tree: She cried (in her anguish): \"Ah! would that I had died before this! would that I had been a thing forgotten and out of sight", romanUrdu: "Phir zachgi (delivery) ki takleef ne usey ek khajoor ke darakht ke nichey pahucha diya. Woh kehne lagi “kaash main issey pehle hi marr jati aur mera naam o nishan na rehta”" },
    { number: 24, arabic: "فَنَادَىٰهَا مِن تَحْتِهَآ أَلَّا تَحْزَنِى قَدْ جَعَلَ رَبُّكِ تَحْتَكِ سَرِيًّۭا", transliteration: "Fanadaha min tahtiha alla tahzanee qad jaAAala rabbuki tahtaki sariyyan", transliterationB: "Fanaadaahaa min tahtihaan allaa tahzanee qad ja'ala Rabbuki tahtaki sariyyaa", english: "But (a voice) cried to her from beneath the (palm-tree): \"Grieve not! for thy Lord hath provided a rivulet beneath thee", romanUrdu: "Farishtey ne paintey (at the foot of her bed) se usko pukar kar kaha “ghum na kar tere Rubb ne tere nichey ek chashma rawan kardiya hai" },
    { number: 25, arabic: "وَهُزِّىٓ إِلَيْكِ بِجِذْعِ ٱلنَّخْلَةِ تُسَٰقِطْ عَلَيْكِ رُطَبًۭا جَنِيًّۭا", transliteration: "Wahuzzee ilayki bijithAAi alnnakhlati tusaqit AAalayki rutaban janiyyan", transliterationB: "Wa huzzeee ilaiki bijiz 'in nakhlati tusaaqit 'alaiki rutaban janiyyaa", english: "And shake towards thyself the trunk of the palm-tree: It will let fall fresh ripe dates upon thee", romanUrdu: "Aur tu zara is darakht ke tanay (trunk) ko hila, tere upar tarr-o-taaza khajoorein tapak padengi" },
    { number: 26, arabic: "فَكُلِى وَٱشْرَبِى وَقَرِّى عَيْنًۭا ۖ فَإِمَّا تَرَيِنَّ مِنَ ٱلْبَشَرِ أَحَدًۭا فَقُولِىٓ إِنِّى نَذَرْتُ لِلرَّحْمَٰنِ صَوْمًۭا فَلَنْ أُكَلِّمَ ٱلْيَوْمَ إِنسِيًّۭا", transliteration: "Fakulee waishrabee waqarree AAaynan faimma tarayinna mina albashari ahadan faqoolee innee nathartu lilrrahmani sawman falan okallima alyawma insiyyan", transliterationB: "Fakulee washrabee wa qarree 'ainaa; fa immaa tarayinnna minal bashari ahadan faqooleee innee nazartu lir Rahmaani sawman falan ukallimal yawma insiyyaa", english: "So eat and drink and cool (thine) eye. And if thou dost see any man, say, 'I have vowed a fast to (Allah) Most Gracious, and this day will I enter into not talk with any human being", romanUrdu: "Pas tu kha aur pee aur apni aankhein thandi kar phir agar koi aadmi tujhey nazar aaye to ussey kehde ke maine rehman ke liye roze ki nazar maani hai, isliye aaj main kisi se na bolungi”" },
    { number: 27, arabic: "فَأَتَتْ بِهِۦ قَوْمَهَا تَحْمِلُهُۥ ۖ قَالُوا۟ يَٰمَرْيَمُ لَقَدْ جِئْتِ شَيْـًۭٔا فَرِيًّۭا", transliteration: "Faatat bihi qawmaha tahmiluhu qaloo ya maryamu laqad jiti shayan fariyyan", transliterationB: "Fa atat bihee qawmahaa tahmiluhoo qaaloo yaa Maryamoo laqad ji'ti shai'an fariyyaa", english: "At length she brought the (babe) to her people, carrying him (in her arms). They said: \"O Mary! truly an amazing thing hast thou brought", romanUrdu: "Phir woh is bacchey ko liye huey apni qaum mein aayi. Log kehne lagey “aey Maryam, yeh tu nay bada paap kar daala" },
    { number: 28, arabic: "يَٰٓأُخْتَ هَٰرُونَ مَا كَانَ أَبُوكِ ٱمْرَأَ سَوْءٍۢ وَمَا كَانَتْ أُمُّكِ بَغِيًّۭا", transliteration: "Ya okhta haroona ma kana abooki imraa sawin wama kanat ommuki baghiyyan", transliterationB: "Yaaa ukkhta Haaroona maa kaana abokim ra-a saw'inw wa maa kaanat ummuki baghiyyaa", english: "O sister of Aaron! Thy father was not a man of evil, nor thy mother a woman unchaste", romanUrdu: "Aey Haroon ki behan, na tera baap koi bura aadmi tha aur na teri Maa hi koi badhkar aurat thi”" },
    { number: 29, arabic: "فَأَشَارَتْ إِلَيْهِ ۖ قَالُوا۟ كَيْفَ نُكَلِّمُ مَن كَانَ فِى ٱلْمَهْدِ صَبِيًّۭا", transliteration: "Faasharat ilayhi qaloo kayfa nukallimu man kana fee almahdi sabiyyan", transliterationB: "Fa ashaarat ilaih; qaaloo kaifa nukallimu man kaana fil mahdi sabiyyaa", english: "But she pointed to the babe. They said: \"How can we talk to one who is a child in the cradle", romanUrdu: "Maryam ne bacchey ki taraf ishara kardiya. Logon ne kaha “hum issey kya baat karein jo gehwarey (cradle) mein pada hua ek baccha hai?”" },
    { number: 30, arabic: "قَالَ إِنِّى عَبْدُ ٱللَّهِ ءَاتَىٰنِىَ ٱلْكِتَٰبَ وَجَعَلَنِى نَبِيًّۭا", transliteration: "Qala innee AAabdu Allahi ataniya alkitaba wajaAAalanee nabiyyan", transliterationB: "Qaala innee 'abdullaahi aataaniyal Kitaaba wa ja'alanee Nabiyyaa", english: "He said: \"I am indeed a servant of Allah: He hath given me revelation and made me a prophet", romanUrdu: "Baccha bol utha “ main Allah ka banda hoon usne mujhey kitab di , aur Nabi banaya" },
    { number: 31, arabic: "وَجَعَلَنِى مُبَارَكًا أَيْنَ مَا كُنتُ وَأَوْصَٰنِى بِٱلصَّلَوٰةِ وَٱلزَّكَوٰةِ مَا دُمْتُ حَيًّۭا", transliteration: "WajaAAalanee mubarakan ayna ma kuntu waawsanee bialssalati waalzzakati ma dumtu hayyan", transliterationB: "Wa ja'alanee mubaarakan aina maa kuntu wa awsaanee bis Salaati waz Zakaati maa dumtu haiyaa", english: "And He hath made me blessed wheresoever I be, and hath enjoined on me Prayer and Charity as long as I live", romanUrdu: "Aur babarakat kiya jahan bhi main rahoon, aur namaz aur zakaat ki pabandi ka hukum diya jab tak main zinda rahoon" },
    { number: 32, arabic: "وَبَرًّۢا بِوَٰلِدَتِى وَلَمْ يَجْعَلْنِى جَبَّارًۭا شَقِيًّۭا", transliteration: "Wabarran biwalidatee walam yajAAalnee jabbaran shaqiyyan", transliterationB: "Wa barram biwaalidatee wa lam yaj'alnee jabbaaran shaqiyyaa", english: "(He) hath made me kind to my mother, and not overbearing or miserable", romanUrdu: "Aur apni walida ka haqq ada karne wala banaya, aur mujhko jabbar (oppressive) aur shaqqi (hard-hearted) nahin banaya" },
    { number: 33, arabic: "وَٱلسَّلَٰمُ عَلَىَّ يَوْمَ وُلِدتُّ وَيَوْمَ أَمُوتُ وَيَوْمَ أُبْعَثُ حَيًّۭا", transliteration: "Waalssalamu AAalayya yawma wulidtu wayawma amootu wayawma obAAathu hayyan", transliterationB: "Wassalaamu 'alaiya yawma wulittu wa yawma amootu wa yawma ub'asu baiyaa", english: "So peace is on me the day I was born, the day that I die, and the day that I shall be raised up to life (again)", romanUrdu: "Salam hai mujhpar jabke main paida hua aur jabke main maroon(die) aur jabke zinda karke uthaya jaoon”" },
    { number: 34, arabic: "ذَٰلِكَ عِيسَى ٱبْنُ مَرْيَمَ ۚ قَوْلَ ٱلْحَقِّ ٱلَّذِى فِيهِ يَمْتَرُونَ", transliteration: "Thalika AAeesa ibnu maryama qawla alhaqqi allathee feehi yamtaroona", transliterationB: "Zaalika 'Eesab-nu Marya; qawlal haqqil lazee feehi yamtaroon", english: "Such (was) Jesus the son of Mary: (it is) a statement of truth, about which they (vainly) dispute", romanUrdu: "Yeh hai Isa ibn Maryam aur yeh hai uske barey mein woh sacchi baat jismein log shakk kar rahey hain" },
    { number: 35, arabic: "مَا كَانَ لِلَّهِ أَن يَتَّخِذَ مِن وَلَدٍۢ ۖ سُبْحَٰنَهُۥٓ ۚ إِذَا قَضَىٰٓ أَمْرًۭا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ", transliteration: "Ma kana lillahi an yattakhitha min waladin subhanahu itha qada amran fainnama yaqoolu lahu kun fayakoonu", transliterationB: "Maa kaana lillaahi ai yattakhiza minw waladin Subhaanah; izaa qadaaa amran fa innamaa yaqoolu lahoo kun fa yakoon", english: "It is not befitting to (the majesty of) Allah that He should beget a son. Glory be to Him! when He determines a matter, He only says to it, \"Be\", and it is", romanUrdu: "Allah ka yeh kaam nahin hai ke woh kisi ko beta banaye. Woh paak zaat hai, woh jab kisi baat ka faisla karta hai to kehta hai ke hoja, aur bas woh ho jati hai" },
    { number: 36, arabic: "وَإِنَّ ٱللَّهَ رَبِّى وَرَبُّكُمْ فَٱعْبُدُوهُ ۚ هَٰذَا صِرَٰطٌۭ مُّسْتَقِيمٌۭ", transliteration: "Wainna Allaha rabbee warabbukum faoAAbudoohu hatha siratun mustaqeemun", transliterationB: "Wa innal laaha Rabbee wa Rabbukum fa'budooh; haazaa Siraatum Mustaqeem", english: "Verily Allah is my Lord and your Lord: Him therefore serve ye: this is a Way that is straight", romanUrdu: "(Aur Isa ne kaha tha ke)”Allah mera Rubb bhi hai aur tumhara Rubb bhi, pas tum usi ki bandagi karo, yahi seedhi raah hai”" },
    { number: 37, arabic: "فَٱخْتَلَفَ ٱلْأَحْزَابُ مِنۢ بَيْنِهِمْ ۖ فَوَيْلٌۭ لِّلَّذِينَ كَفَرُوا۟ مِن مَّشْهَدِ يَوْمٍ عَظِيمٍ", transliteration: "Faikhtalafa alahzabu min baynihim fawaylun lillatheena kafaroo min mashhadi yawmin AAatheemin", transliterationB: "Fakhtalafal ahzaabu mim bainihim fawailul lillazeena kafaroo mim mashhadi Yawmin 'azeem", english: "But the sects differ among themselves: and woe to the unbelievers because of the (coming) Judgment of a Momentous Day", romanUrdu: "Magar phir mukhtalif giroh baham ikhtilaf karne lagey. So jin logon ne kufr kiya unke liye woh waqt badi tabahi ka hoga" },
    { number: 38, arabic: "أَسْمِعْ بِهِمْ وَأَبْصِرْ يَوْمَ يَأْتُونَنَا ۖ لَٰكِنِ ٱلظَّٰلِمُونَ ٱلْيَوْمَ فِى ضَلَٰلٍۢ مُّبِينٍۢ", transliteration: "AsmiAA bihim waabsir yawma yatoonana lakini alththalimoona alyawma fee dalalin mubeenin", transliterationB: "Asmi' bihim wa absir Yawma yaatoonanaa laakiniz zaalimoonal yawma fee dalaalim mubeen", english: "How plainly will they see and hear, the Day that they will appear before Us! but the unjust today are in error manifest", romanUrdu: "Jabke woh ek bada din dekhenge, jab woh hamare saamne hazir hongey us roz to unke kaan bhi khoob sun rahey hongey aur unki aankhein bhi khoob dekhti hongi, magar aaj yeh zalim khuli gumraahi mein mubtila hain" },
    { number: 39, arabic: "وَأَنذِرْهُمْ يَوْمَ ٱلْحَسْرَةِ إِذْ قُضِىَ ٱلْأَمْرُ وَهُمْ فِى غَفْلَةٍۢ وَهُمْ لَا يُؤْمِنُونَ", transliteration: "Waanthirhum yawma alhasrati ith qudiya alamru wahum fee ghaflatin wahum la yuminoona", transliterationB: "Wa anzirhum Yawmal hasrati iz qudiyal amr; wa hum fee ghaflatinw wa hum laa yu'minoon", english: "But warn them of the Day of Distress, when the matter will be determined: for (behold,) they are negligent and they do not believe", romanUrdu: "(Aey Muhammad), is halat mein jabke yeh log gafil hain aur iman nahin la rahey hain, inhein us din se dara do jabke faisla kardiya jayega aur pachtawe ke siwa koi chara-e-kaar na hoga" },
    { number: 40, arabic: "إِنَّا نَحْنُ نَرِثُ ٱلْأَرْضَ وَمَنْ عَلَيْهَا وَإِلَيْنَا يُرْجَعُونَ", transliteration: "Inna nahnu narithu alarda waman AAalayha wailayna yurjaAAoona", transliterationB: "Innaa NNahnu narisul arda wa man 'alaihaa wa ilainaa yurja'oon", english: "It is We Who will inherit the earth, and all beings thereon: to Us will they all be returned", romanUrdu: "Aakhir-e-kaar hum hi zameen aur uski sari cheezon ke waris hongey aur sab hamari taraf hi paltaye jayenge" },
    { number: 41, arabic: "وَٱذْكُرْ فِى ٱلْكِتَٰبِ إِبْرَٰهِيمَ ۚ إِنَّهُۥ كَانَ صِدِّيقًۭا نَّبِيًّا", transliteration: "Waothkur fee alkitabi ibraheema innahu kana siddeeqan nabiyyan", transliterationB: "Wazkur fil Kitaabi Ibraaheem; innahoo kaana siddeeqan Nabiyyaa", english: "Also mention in the Book (the story of) Abraham: He was a man of Truth, a prophet", romanUrdu: "Aur is kitaab mein Ibrahim ka qissa bayan karo, beshak woh ek raast-baaz Insaan aur ek Nabi tha" },
    { number: 42, arabic: "إِذْ قَالَ لِأَبِيهِ يَٰٓأَبَتِ لِمَ تَعْبُدُ مَا لَا يَسْمَعُ وَلَا يُبْصِرُ وَلَا يُغْنِى عَنكَ شَيْـًۭٔا", transliteration: "Ith qala liabeehi ya abati lima taAAbudu ma la yasmaAAu wala yubsiru wala yughnee AAanka shayan", transliterationB: "Iz qaala li abeehi yaaa abati lima ta'budu maa laa yasma'u wa laa yubsiru wa laa yughnee 'anka shai'aa", english: "Behold, he said to his father: \"O my father! why worship that which heareth not and seeth not, and can profit thee nothing", romanUrdu: "(Inhein zara us mauqe ki yaad dilao) jabke usne apne baap se kaha ke “Abbajaan, aap kyun un cheezon ki ibadat karte hain jo na sunti hain na dekhti hain aur na aap ka koi kaam bana sakti hain" },
    { number: 43, arabic: "يَٰٓأَبَتِ إِنِّى قَدْ جَآءَنِى مِنَ ٱلْعِلْمِ مَا لَمْ يَأْتِكَ فَٱتَّبِعْنِىٓ أَهْدِكَ صِرَٰطًۭا سَوِيًّۭا", transliteration: "Ya abati innee qad jaanee mina alAAilmi ma lam yatika faittabiAAnee ahdika siratan sawiyyan", transliterationB: "Yaaa abati innee qad jaaa'anee minal 'ilmi maa lam yaatika fattabi'neee ahdika siraatan Sawiyyaa", english: "O my father! to me hath come knowledge which hath not reached thee: so follow me: I will guide thee to a way that is even and straight", romanUrdu: "Abbajaan, mere paas ek aisa ilam aaya hai jo aapke paas nahin aaya, aap mere peechey chalein , main aapko seedha raasta bataunga" },
    { number: 44, arabic: "يَٰٓأَبَتِ لَا تَعْبُدِ ٱلشَّيْطَٰنَ ۖ إِنَّ ٱلشَّيْطَٰنَ كَانَ لِلرَّحْمَٰنِ عَصِيًّۭا", transliteration: "Ya abati la taAAbudi alshshaytana inna alshshaytana kana lilrrahmani AAasiyyan", transliterationB: "Yaaa abati laa ta'budish Shaitaana innash Shaitaana kaana lir Rahmaani 'asiyyaa", english: "O my father! serve not Satan: for Satan is a rebel against (Allah) Most Gracious", romanUrdu: "Abbajaan!aap shaytan ki bandagi na karein, shaytan to rehman ka nafarman hai" },
    { number: 45, arabic: "يَٰٓأَبَتِ إِنِّىٓ أَخَافُ أَن يَمَسَّكَ عَذَابٌۭ مِّنَ ٱلرَّحْمَٰنِ فَتَكُونَ لِلشَّيْطَٰنِ وَلِيًّۭا", transliteration: "Ya abati innee akhafu an yamassaka AAathabun mina alrrahmani fatakoona lilshshyatani waliyyan", transliterationB: "Yaaa abati innee akhaafu ai yamssaka 'azaabum minar Rahmaani fatakoona lish Shaitaani waliyyaa", english: "O my father! I fear lest a Penalty afflict thee from (Allah) Most Gracious, so that thou become to Satan a friend", romanUrdu: "Abbajaan, mujhey darr hai ke kahin aap rehman ke azaab mein mubtila na ho jayein aur shaytan ke saathi ban kar rahein”" },
    { number: 46, arabic: "قَالَ أَرَاغِبٌ أَنتَ عَنْ ءَالِهَتِى يَٰٓإِبْرَٰهِيمُ ۖ لَئِن لَّمْ تَنتَهِ لَأَرْجُمَنَّكَ ۖ وَٱهْجُرْنِى مَلِيًّۭا", transliteration: "Qala araghibun anta AAan alihatee ya ibraheemu lain lam tantahi laarjumannaka waohjurnee maliyyan", transliterationB: "Qaala araaghibun anta 'an aalihatee yaaa Ibraaheemu la 'il lam tantahi la arjumannaka wahjumee maliyyaa", english: "(The father) replied: \"Dost thou hate my gods, O Abraham? If thou forbear not, I will indeed stone thee: Now get away from me for a good long while", romanUrdu: "Baap ne kaha “Ibrahim, kya tu mere maboodon se phir gaya hai? Agar tu baaz na aaya to main tujhey sangsar(stone you to death) kardunga. Bas tu hamesha ke liye mujhse alag ho jaa”" },
    { number: 47, arabic: "قَالَ سَلَٰمٌ عَلَيْكَ ۖ سَأَسْتَغْفِرُ لَكَ رَبِّىٓ ۖ إِنَّهُۥ كَانَ بِى حَفِيًّۭا", transliteration: "Qala salamun AAalayka saastaghfiru laka rabbee innahu kana bee hafiyyan", transliterationB: "Qaala salaamun 'alaika sa astaghfiru laka Rabbeee innahoo kaana bee hafiyyaa", english: "Abraham said: \"Peace be on thee: I will pray to my Lord for thy forgiveness: for He is to me Most Gracious", romanUrdu: "Ibrahim ne kaha “Salaam hai aapko, main apne Rubb se dua karoonga ke aapko maaf karde. Mera Rubb mujhpar bada hi meharban hai" },
    { number: 48, arabic: "وَأَعْتَزِلُكُمْ وَمَا تَدْعُونَ مِن دُونِ ٱللَّهِ وَأَدْعُوا۟ رَبِّى عَسَىٰٓ أَلَّآ أَكُونَ بِدُعَآءِ رَبِّى شَقِيًّۭا", transliteration: "WaaAAtazilukum wama tadAAoona min dooni Allahi waadAAoo rabbee AAasa alla akoona biduAAai rabbee shaqiyyan", transliterationB: "Wa a'tazilukum wa maa tad'oona min doonil laahi wa ad'o Rabbee 'asaaa allaaa akoona bidu'aaa'i Rabbee shaqiyyaa", english: "And I will turn away from you (all) and from those whom ye invoke besides Allah: I will call on my Lord: perhaps, by my prayer to my Lord, I shall be not unblest", romanUrdu: "Main aap logon ko bhi chodhta hoon aur un hastiyon ko bhi jinhein aap log khuda ko chodh kar pukara karte hain. Main to apne Rubb hi ko pukarunga , umeed hai ke main apne Rubb ko pukar ke na-murad na rahunga”" },
    { number: 49, arabic: "فَلَمَّا ٱعْتَزَلَهُمْ وَمَا يَعْبُدُونَ مِن دُونِ ٱللَّهِ وَهَبْنَا لَهُۥٓ إِسْحَٰقَ وَيَعْقُوبَ ۖ وَكُلًّۭا جَعَلْنَا نَبِيًّۭا", transliteration: "Falamma iAAtazalahum wama yaAAbudoona min dooni Allahi wahabna lahu ishaqa wayaAAqooba wakullan jaAAalna nabiyyan", transliterationB: "Falamma' tazalahum wa maa ya'budoona min doonil laahi wahabnaa lahoo is-haaqa wa ya'qoob, wa kullan ja'alnaa Nabiyyaa", english: "When he had turned away from them and from those whom they worshipped besides Allah, We bestowed on him Isaac and Jacob, and each one of them We made a prophet", romanUrdu: "Pas jab woh un logon se aur unke maboodane gair Allah se juda ho gaya to humne usko Ishaaq aur Yakub jaisi aulad di aur har ek ko Nabi banaya" },
    { number: 50, arabic: "وَوَهَبْنَا لَهُم مِّن رَّحْمَتِنَا وَجَعَلْنَا لَهُمْ لِسَانَ صِدْقٍ عَلِيًّۭا", transliteration: "Wawahabna lahum min rahmatina wajaAAalna lahum lisana sidqin AAaliyyan", transliterationB: "Wa wahabnaa lahum mirrahmatinaa wa ja'alnaa lahum lisaana sidqin 'aliyyaa", english: "And We bestowed of Our Mercy on them, and We granted them lofty honour on the tongue of truth", romanUrdu: "Aur unko apni rehmat se nawaza aur unko sacchi naamwari ata ki" },
    { number: 51, arabic: "وَٱذْكُرْ فِى ٱلْكِتَٰبِ مُوسَىٰٓ ۚ إِنَّهُۥ كَانَ مُخْلَصًۭا وَكَانَ رَسُولًۭا نَّبِيًّۭا", transliteration: "Waothkur fee alkitabi moosa innahu kana mukhlasan wakana rasoolan nabiyyan", transliterationB: "Wazkur fil Kitaabi Moosaaa; innahoo kaana mukhlasanw wa kaana Rasoolan Nabiyyaa", english: "Also mention in the Book (the story of) Moses: for he was specially chosen, and he was a messenger (and) a prophet", romanUrdu: "Aur zikr karo is kitaab mein Moosa ka, woh ek cheeda (chosen) shaks tha aur Rasool Nabi tha" },
    { number: 52, arabic: "وَنَٰدَيْنَٰهُ مِن جَانِبِ ٱلطُّورِ ٱلْأَيْمَنِ وَقَرَّبْنَٰهُ نَجِيًّۭا", transliteration: "Wanadaynahu min janibi alttoori alaymani waqarrabnahu najiyyan", transliterationB: "Wa naadainaahu min jaanibit Tooril aimani wa qarrabnaahu najiyyaa", english: "And we called him from the right side of Mount (Sinai), and made him draw near to Us, for mystic (converse)", romanUrdu: "Humne usko Tur ke dahini(right) janib se pukara aur raaz ki guftagu se usko takarrub (honour) ata kiya" },
    { number: 53, arabic: "وَوَهَبْنَا لَهُۥ مِن رَّحْمَتِنَآ أَخَاهُ هَٰرُونَ نَبِيًّۭا", transliteration: "Wawahabna lahu min rahmatina akhahu haroona nabiyyan", transliterationB: "Wa wahabnaa lahoo mir rahmatinaaa akhaahu Haaroona Nabiyyaa", english: "And, out of Our Mercy, We gave him his brother Aaron, (also) a prophet", romanUrdu: "Aur apni mehrabani se uske bhai Haroon ko Nabi bana kar usey (madadgaar ke taur par) diya" },
    { number: 54, arabic: "وَٱذْكُرْ فِى ٱلْكِتَٰبِ إِسْمَٰعِيلَ ۚ إِنَّهُۥ كَانَ صَادِقَ ٱلْوَعْدِ وَكَانَ رَسُولًۭا نَّبِيًّۭا", transliteration: "Waothkur fee alkitabi ismaAAeela innahu kana sadiqa alwaAAdi wakana rasoolan nabiyyan", transliterationB: "Wazkur fil Kitaabi ismaa'eel; innahoo kaana saadiqal wa'di wa kaana Rasoolan Nabiyyaa", english: "Also mention in the Book (the story of) Isma'il: He was (strictly) true to what he promised, and he was a messenger (and) a prophet", romanUrdu: "Aur is kitaab mein Ismail ka zir karo, woh wadey ka saccha tha aur Rasool Nabi tha" },
    { number: 55, arabic: "وَكَانَ يَأْمُرُ أَهْلَهُۥ بِٱلصَّلَوٰةِ وَٱلزَّكَوٰةِ وَكَانَ عِندَ رَبِّهِۦ مَرْضِيًّۭا", transliteration: "Wakana yamuru ahlahu bialssalati waalzzakati wakana AAinda rabbihi mardiyyan", transliterationB: "Wa kaana yaamuru ahlahoo bis Salaati waz zakaati wa kaana 'inda Rabbihee mardiyyaa", english: "He used to enjoin on his people Prayer and Charity, and he was most acceptable in the sight of his Lord", romanUrdu: "Woh apne ghar walon ko namaz aur zakat ka hukum deta tha aur apne Rubb ke nazdeek ek pasandeeda Insaan tha" },
    { number: 56, arabic: "وَٱذْكُرْ فِى ٱلْكِتَٰبِ إِدْرِيسَ ۚ إِنَّهُۥ كَانَ صِدِّيقًۭا نَّبِيًّۭا", transliteration: "Waothkur fee alkitabi idreesa innahu kana siddeeqan nabiyyan", transliterationB: "Wazkur fil Kitaabi Idrees; innahoo kaana siddeeqan Nabiyyaa", english: "Also mention in the Book the case of Idris: He was a man of truth (and sincerity), (and) a prophet", romanUrdu: "Aur is kitaab mein Idris ka zikr karo, woh ek raast-baaz (righteous) Insaan aur ek Nabi tha" },
    { number: 57, arabic: "وَرَفَعْنَٰهُ مَكَانًا عَلِيًّا", transliteration: "WarafaAAnahu makanan AAaliyyan", transliterationB: "Wa rafa'naahu makaanan 'aliyyaa", english: "And We raised him to a lofty station", romanUrdu: "Aur usey humne buland muqaam par uthaya tha" },
    { number: 58, arabic: "أُو۟لَٰٓئِكَ ٱلَّذِينَ أَنْعَمَ ٱللَّهُ عَلَيْهِم مِّنَ ٱلنَّبِيِّۦنَ مِن ذُرِّيَّةِ ءَادَمَ وَمِمَّنْ حَمَلْنَا مَعَ نُوحٍۢ وَمِن ذُرِّيَّةِ إِبْرَٰهِيمَ وَإِسْرَٰٓءِيلَ وَمِمَّنْ هَدَيْنَا وَٱجْتَبَيْنَآ ۚ إِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَٰتُ ٱلرَّحْمَٰنِ خَرُّوا۟ سُجَّدًۭا وَبُكِيًّۭا ۩", transliteration: "Olaika allatheena anAAama Allahu AAalayhim mina alnnabiyyeena min thurriyyati adama wamimman hamalna maAAa noohin wamin thurriyyati ibraheema waisraeela wamimman hadayna waijtabayna itha tutla AAalayhim ayatu alrrahmani kharroo sujjadan wabukiyyan", transliterationB: "Ulaaa'ikal lazeena an'amal laahu 'alaihim minan Nabiyyeena min zurriyyati Aadama wa mimman hamalnaa ma'a Noohinw wa min zurriyyati Ibraaheema wa Israaa'eela wa mimman hadainaa wajta bainaaa; izaa tutlaa 'alaihim Aayaatur Rahmaani kharroo sujjadanw wa bukiyyaa", english: "Those were some of the prophets on whom Allah did bestow His Grace,- of the posterity of Adam, and of those who We carried (in the Ark) with Noah, and of the posterity of Abraham and Israel of those whom We guided and chose. Whenever the Signs of (Allah) Most Gracious were rehearsed to them, they would fall down in prostrate adoration and in tears", romanUrdu: "Yeh woh paigambar hain jinpar Allah ne inaam farmaya Adam ki aulad mein se, aur un logon ki nasal se jinhein humne Nooh ke saath kashti par sawaar kiya tha, aur Ibrahim ki nasal se aur Israel ki nasal se aur yeh un logon mein se thay jinko humne hidayat bakshi aur barguzida kiya.Inka haal yeh tha ke jab rehman ki aayat unko sunayi jati to rotey huey sajde mein gir jatey thay" },
    { number: 59, arabic: "۞ فَخَلَفَ مِنۢ بَعْدِهِمْ خَلْفٌ أَضَاعُوا۟ ٱلصَّلَوٰةَ وَٱتَّبَعُوا۟ ٱلشَّهَوَٰتِ ۖ فَسَوْفَ يَلْقَوْنَ غَيًّا", transliteration: "Fakhalafa min baAAdihim khalfun adaAAoo alssalata waittabaAAoo alshshahawati fasawfa yalqawna ghayyan", transliterationB: "Fakhalafa mim ba'dihim khalfun adaa'us Salaata wattaba'ush shahawaati fasawfa yalqawna ghaiyaa", english: "But after them there followed a posterity who missed prayers and followed after lusts soon, then, will they face Destruction", romanUrdu: "Phir inke baad woh nakhalf (degenerate) log inke jaansaheen (sucessors) huey jinhon ne namaz ko zaya kiya aur khwahishat e nafs ki pairwi ki. Pas qareeb hai ke woh gumraahi ke anjaam se do-char hon" },
    { number: 60, arabic: "إِلَّا مَن تَابَ وَءَامَنَ وَعَمِلَ صَٰلِحًۭا فَأُو۟لَٰٓئِكَ يَدْخُلُونَ ٱلْجَنَّةَ وَلَا يُظْلَمُونَ شَيْـًۭٔا", transliteration: "Illa man taba waamana waAAamila salihan faolaika yadkhuloona aljannata wala yuthlamoona shayan", transliterationB: "Illaa man taaba wa aamana wa 'amila saalihan fa ulaaa'ika yadkhuloonal jannata wa laa yuzlamoona shai'aa", english: "Except those who repent and believe, and work righteousness: for these will enter the Garden and will not be wronged in the least", romanUrdu: "Albatta jo tawba karlein aur iman le aayein aur neik amali ikhtiyar karlein woh jannat mein dakhil hongey aur unki zarra barabar haqq talafi na hogi" },
    { number: 61, arabic: "جَنَّٰتِ عَدْنٍ ٱلَّتِى وَعَدَ ٱلرَّحْمَٰنُ عِبَادَهُۥ بِٱلْغَيْبِ ۚ إِنَّهُۥ كَانَ وَعْدُهُۥ مَأْتِيًّۭا", transliteration: "Jannati AAadnin allatee waAAada alrrahmanu AAibadahu bialghaybi innahu kana waAAduhu matiyyan", transliterationB: "Jannaati 'adninil latee wa'adar Rahmaanu ibaadahoo bilghaib; innahoo kaana wa'duhoo maatiyyaa", english: "Gardens of Eternity, those which (Allah) Most Gracious has promised to His servants in the Unseen: for His promise must (necessarily) come to pass", romanUrdu: "Inke liye hamesha rehne wali jannatein hain jinka rehman ne apne bandon se dar-purda wada kar rakkha hai aur yaqeenan yeh wada poora hokar rehna hai" },
    { number: 62, arabic: "لَّا يَسْمَعُونَ فِيهَا لَغْوًا إِلَّا سَلَٰمًۭا ۖ وَلَهُمْ رِزْقُهُمْ فِيهَا بُكْرَةًۭ وَعَشِيًّۭا", transliteration: "La yasmaAAoona feeha laghwan illa salaman walahum rizquhum feeha bukratan waAAashiyyan", transliterationB: "Laa yasma'oona feehaa laghwan illaa salaamaa; wa lahum rizquhum feehaa bukratanw wa 'ashiyyaa", english: "They will not there hear any vain discourse, but only salutations of Peace: And they will have therein their sustenance, morning and evening", romanUrdu: "Wahan woh koi behuda baat na sunenge , jo kuch bhi sunenge theek hi sunenge aur unka rizq unhein paiham subh-o-shaam milta rahega" },
    { number: 63, arabic: "تِلْكَ ٱلْجَنَّةُ ٱلَّتِى نُورِثُ مِنْ عِبَادِنَا مَن كَانَ تَقِيًّۭا", transliteration: "Tilka aljannatu allatee noorithu min AAibadina man kana taqiyyan", transliterationB: "Tilkal jannatul latee oorisu min 'ibaadinaa man kaana taqiyyaa", english: "Such is the Garden which We give as an inheritance to those of Our servants who guard against Evil", romanUrdu: "Yeh hai woh jannat jiska waris hum apne bandon mein se usko banayenge jo parheizgaar raha hai" },
    { number: 64, arabic: "وَمَا نَتَنَزَّلُ إِلَّا بِأَمْرِ رَبِّكَ ۖ لَهُۥ مَا بَيْنَ أَيْدِينَا وَمَا خَلْفَنَا وَمَا بَيْنَ ذَٰلِكَ ۚ وَمَا كَانَ رَبُّكَ نَسِيًّۭا", transliteration: "Wama natanazzalu illa biamri rabbika lahu ma bayna aydeena wama khalfana wama bayna thalika wama kana rabbuka nasiyyan", transliterationB: "Wa maa natanazzalu illaa bi amri Rabbika lahoo maa baina aideenaa wa maa khalfanaa wa maa baina zaalik; wa maa kaana Rabbuka nasiyyaa", english: "(The angels say:) \"We descend not but by command of thy Lord: to Him belongeth what is before us and what is behind us, and what is between: and thy Lord never doth forget", romanUrdu: "(Aey Muhammad), hum tumhare Rubb ke hukum ke bagair nahin utra karte, jo kuch hamare aage hai aur jo kuch peechey hai aur jo kuch iske darmiyan mein hai har cheez ka maalik wahi hai aur tumhara Rubb bhoolne wala nahin hai" },
    { number: 65, arabic: "رَّبُّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا فَٱعْبُدْهُ وَٱصْطَبِرْ لِعِبَٰدَتِهِۦ ۚ هَلْ تَعْلَمُ لَهُۥ سَمِيًّۭا", transliteration: "Rabbu alssamawati waalardi wama baynahuma faoAAbudhu waistabir liAAibadatihi hal taAAlamu lahu samiyyan", transliterationB: "Rabbus samaawaati wal ardi wa maa bainahumaa fa'bud hu wastabir li'ibaadatih; hal ta'lamu lahoo samiyyaa", english: "Lord of the heavens and of the earth, and of all that is between them; so worship Him, and be constant and patient in His worship: knowest thou of any who is worthy of the same Name as He", romanUrdu: "Woh Rubb hai aasmano ka aur zameen ka aur un saari cheezon ka jo aasman o zameen ke darmiyan hain, pas tum uski bandagi karo aur usi ki bangadi par sabit qadam raho. Kya hai koi hasti tumhare ilm mein iski hum paya (equal in rank to him)" },
    { number: 66, arabic: "وَيَقُولُ ٱلْإِنسَٰنُ أَءِذَا مَا مِتُّ لَسَوْفَ أُخْرَجُ حَيًّا", transliteration: "Wayaqoolu alinsanu aitha ma mittu lasawfa okhraju hayyan", transliterationB: "Wa yaqoolul insaanu 'aizaa maa mittu lasawfa ukhraju haiyaa", english: "Man says: \"What! When I am dead, shall I then be raised up alive", romanUrdu: "Insaan kehta hai kya waqai jab main mar chukunga to phir zinda karke nikal laya jaunga" },
    { number: 67, arabic: "أَوَلَا يَذْكُرُ ٱلْإِنسَٰنُ أَنَّا خَلَقْنَٰهُ مِن قَبْلُ وَلَمْ يَكُ شَيْـًۭٔا", transliteration: "Awala yathkuru alinsanu anna khalaqnahu min qablu walam yaku shayan", transliterationB: "awalaa yazkurul insaanu annaa khalaqnaahu min qablu wa lam yaku shai'aa", english: "But does not man call to mind that We created him before out of nothing", romanUrdu: "Kya Insaan ko yaad nahin aata ke hum pehle usko paida kar chuke hain jabke woh kuch bhi na tha" },
    { number: 68, arabic: "فَوَرَبِّكَ لَنَحْشُرَنَّهُمْ وَٱلشَّيَٰطِينَ ثُمَّ لَنُحْضِرَنَّهُمْ حَوْلَ جَهَنَّمَ جِثِيًّۭا", transliteration: "Fawarabbika lanahshurannahum waalshshayateena thumma lanuhdirannahum hawla jahannama jithiyyan", transliterationB: "Fawa Rabbika lanahshu rannahum wash shayaateena summa lanuhdirannahum hawla jahannama jisiyyaa", english: "So, by thy Lord, without doubt, We shall gather them together, and (also) the Evil Ones (with them); then shall We bring them forth on their knees round about Hell", romanUrdu: "Tere Rubb ki kasam , hum zaroor un sab ko aur unke saath shayateen ko bhi gher layenge, phir jahannum ke gird laa kar inhein ghutno (knees) ke bal gira denge" },
    { number: 69, arabic: "ثُمَّ لَنَنزِعَنَّ مِن كُلِّ شِيعَةٍ أَيُّهُمْ أَشَدُّ عَلَى ٱلرَّحْمَٰنِ عِتِيًّۭا", transliteration: "Thumma lananziAAanna min kulli sheeAAatin ayyuhum ashaddu AAala alrrahmani AAitiyyan", transliterationB: "Summa lananzi 'anna min kulli shee'atin aiyuhum ashaddu 'alar Rahmaani 'itiyyaa", english: "Then shall We certainly drag out from every sect all those who were worst in obstinate rebellion against (Allah) Most Gracious", romanUrdu: "Phir har giroh mein se har us shaks ko chaant lenge (pick out) jo rehman ke muqable mein zyada sarkash bana hua tha" },
    { number: 70, arabic: "ثُمَّ لَنَحْنُ أَعْلَمُ بِٱلَّذِينَ هُمْ أَوْلَىٰ بِهَا صِلِيًّۭا", transliteration: "Thumma lanahnu aAAlamu biallatheena hum awla biha siliyyan", transliterationB: "Summa lanahnu a'lamu billazeena hum awlaa bihaa siliyyaa", english: "And certainly We know best those who are most worthy of being burned therein", romanUrdu: "Phir hum yeh jaante hain ke in mein se kaun sabse badhkar jahannum mein jhonke janey ka mustahiq hai" },
    { number: 71, arabic: "وَإِن مِّنكُمْ إِلَّا وَارِدُهَا ۚ كَانَ عَلَىٰ رَبِّكَ حَتْمًۭا مَّقْضِيًّۭا", transliteration: "Wain minkum illa wariduha kana AAala rabbika hatman maqdiyyan", transliterationB: "Wa im minkum illaa waa riduhaa; kaana 'alaa Rabbika hatmam maqdiyyaa", english: "Not one of you but will pass over it: this is, with thy Lord, a Decree which must be accomplished", romanUrdu: "Tum mein se koi nahin hai jo jahannum par warid na ho,yeh to ek tai shuda baat hai jisey pura karna tere Rubb ka zimma hai" },
    { number: 72, arabic: "ثُمَّ نُنَجِّى ٱلَّذِينَ ٱتَّقَوا۟ وَّنَذَرُ ٱلظَّٰلِمِينَ فِيهَا جِثِيًّۭا", transliteration: "Thumma nunajjee allatheena ittaqaw wanatharu alththalimeena feeha jithiyyan", transliterationB: "Summa nunajjil lazeenat taqaw wa nazaruz zaalimeena feehaa jisiyyaa", english: "But We shall save those who guarded against evil, and We shall leave the wrong-doers therein, (humbled) to their knees", romanUrdu: "Phir hum un logon ko bacha lenge jo (duniya mein ) muttaqi thay aur zalimon ko usi mein gira hua chodh denge" },
    { number: 73, arabic: "وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَٰتُنَا بَيِّنَٰتٍۢ قَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوٓا۟ أَىُّ ٱلْفَرِيقَيْنِ خَيْرٌۭ مَّقَامًۭا وَأَحْسَنُ نَدِيًّۭا", transliteration: "Waitha tutla AAalayhim ayatuna bayyinatin qala allatheena kafaroo lillatheena amanoo ayyu alfareeqayni khayrun maqaman waahsanu nadiyyan", transliterationB: "Wa izaa tutlaa 'alaihim Aayaatunaa baiyinaatin qaalal lazeena kafaroo lillazeena aamanooo aiyul fareeqaini khairum maqaamanw wa ahsanu nadiyyaa", english: "When Our Clear Signs are rehearsed to them, the Unbelievers say to those who believe, \"Which of the two sides is best in point of position? Which makes the best show in council", romanUrdu: "In logon ko jab hamari khuli khuli aayat sunayi jati hain to inkar karne waley iman laney walon se kehte hain “batao, hum dono girohon mein se kaun behtar halat mein hai aur kiski majlisein zyada shandaar hai?”" },
    { number: 74, arabic: "وَكَمْ أَهْلَكْنَا قَبْلَهُم مِّن قَرْنٍ هُمْ أَحْسَنُ أَثَٰثًۭا وَرِءْيًۭا", transliteration: "Wakam ahlakna qablahum min qarnin hum ahsanu athathan wariyan", transliterationB: "Wa kam ahlaknaa qablahum min qarnin hum ahsanu asaasanw wa ri'yaa", english: "But how many (countless) generations before them have we destroyed, who were even better in equipment and in glitter to the eye", romanUrdu: "Halanke insey pehle hum kitni hi aisi qaumo ko halaak kar chuke hain jo insey zyada sar-o-samaan rakhti thin aur zahiri shaan o shaukat mein insey badi hui thi" },
    { number: 75, arabic: "قُلْ مَن كَانَ فِى ٱلضَّلَٰلَةِ فَلْيَمْدُدْ لَهُ ٱلرَّحْمَٰنُ مَدًّا ۚ حَتَّىٰٓ إِذَا رَأَوْا۟ مَا يُوعَدُونَ إِمَّا ٱلْعَذَابَ وَإِمَّا ٱلسَّاعَةَ فَسَيَعْلَمُونَ مَنْ هُوَ شَرٌّۭ مَّكَانًۭا وَأَضْعَفُ جُندًۭا", transliteration: "Qul man kana fee alddalalati falyamdud lahu alrrahmanu maddan hatta itha raaw ma yooAAadoona imma alAAathaba waimma alssaAAata fasayaAAlamoona man huwa sharrun makanan waadAAafu jundan", transliterationB: "Qul man kaana fidda laalati falyamdud lahur Rahmaanu maddaa; hattaaa izaa ra aw maa yoo'adoona immal 'azaaba wa immas Saa'ata fasa ya'lamoona man huwa sharrum makaananw wa ad'afu jundaa", english: "Say: \"If any men go astray, (Allah) Most Gracious extends (the rope) to them, until, when they see the warning of Allah (being fulfilled) - either in punishment or in (the approach of) the Hour,- they will at length realise who is worst in position, and (who) weakest in forces", romanUrdu: "Insey kaho, jo shaks gumraahi mein mubtila hota hai usey Rehman dheel diya karta hai, yahan tak ke jab aisey log woh cheez dekh letay hain jiska unse wada kiya gaya hai khwa woh azaab e ilahi ho ya qayamat ki ghadi tab unhein maloom ho jata hai ke kiska haal kharab hai aur kiska jattha (party) kamzor" },
    { number: 76, arabic: "وَيَزِيدُ ٱللَّهُ ٱلَّذِينَ ٱهْتَدَوْا۟ هُدًۭى ۗ وَٱلْبَٰقِيَٰتُ ٱلصَّٰلِحَٰتُ خَيْرٌ عِندَ رَبِّكَ ثَوَابًۭا وَخَيْرٌۭ مَّرَدًّا", transliteration: "Wayazeedu Allahu allatheena ihtadaw hudan waalbaqiyatu alssalihatu khayrun AAinda rabbika thawaban wakhayrun maraddan", transliterationB: "Wa yazeedul laahul lazeenah tadaw hudaa; wal baaqiyaatus saalihaatu khairun 'inda Rabbika sawaabanw wa khairum maraddaa", english: "And Allah doth advance in guidance those who seek guidance: and the things that endure, Good Deeds, are best in the sight of thy Lord, as rewards, and best in respect of (their) eventual return", romanUrdu: "Iske baraks jo logo raah e raast ikhtiyar karte hain Allah unko raast-rawi mein taraqqi ata farmata hai aur baaqi reh janey wali nekiyan hi tere Rubb ke nazdeek jaza aur anjaam ke aitbaar se behtar hain" },
    { number: 77, arabic: "أَفَرَءَيْتَ ٱلَّذِى كَفَرَ بِـَٔايَٰتِنَا وَقَالَ لَأُوتَيَنَّ مَالًۭا وَوَلَدًا", transliteration: "Afaraayta allathee kafara biayatina waqala laootayanna malan wawaladan", transliterationB: "Afara'aytal lazee kafara bi Aayaatinaa wa qaala la oota yanna maalanw wa waladaa", english: "Hast thou then seen the (sort of) man who rejects Our Signs, yet says: \"I shall certainly be given wealth and children", romanUrdu: "Phir tu nay dekha us shaks ko jo hamari aayat ko manney se inkar karta hai aur kehta hai ke main to maal aur aulad se nawaza hi jata rahunga" },
    { number: 78, arabic: "أَطَّلَعَ ٱلْغَيْبَ أَمِ ٱتَّخَذَ عِندَ ٱلرَّحْمَٰنِ عَهْدًۭا", transliteration: "AttalaAAa alghayba ami ittakhatha AAinda alrrahmani AAahdan", transliterationB: "Attala'al ghaiba amitta khaza'indar Rahmaani 'ahdaa", english: "Has he penetrated to the Unseen, or has he taken a contract with (Allah) Most Gracious", romanUrdu: "Kya usey gaib ka pata chal gaya hai ya usne rehman se koi ahad le rakkha hai" },
    { number: 79, arabic: "كَلَّا ۚ سَنَكْتُبُ مَا يَقُولُ وَنَمُدُّ لَهُۥ مِنَ ٱلْعَذَابِ مَدًّۭا", transliteration: "Kalla sanaktubu ma yaqoolu wanamuddu lahu mina alAAathabi maddan", transliterationB: "Kallaa; sanaktubu maa yaqoolu wa namuddu lahoo minal 'azaabi maddaa", english: "Nay! We shall record what he says, and We shall add and add to his punishment", romanUrdu: "Hargiz nahin, jo kuch yeh bakhta (boasts of) hai isey hum likh lengey aur iske liye saza mein aur zyada izafa karenge" },
    { number: 80, arabic: "وَنَرِثُهُۥ مَا يَقُولُ وَيَأْتِينَا فَرْدًۭا", transliteration: "Wanarithuhu ma yaqoolu wayateena fardan", transliterationB: "Wa narisuhoo maa yaqoolu wa yaateenaa fardaa", english: "To Us shall return all that he talks of and he shall appear before Us bare and alone", romanUrdu: "Jis sar-o-samaan aur laao lashkar ka yeh zikr kar raha hai woh sab hamare paas reh jayega aur yeh akela hamare saamne hazir hoga" },
    { number: 81, arabic: "وَٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ ءَالِهَةًۭ لِّيَكُونُوا۟ لَهُمْ عِزًّۭا", transliteration: "Waittakhathoo min dooni Allahi alihatan liyakoonoo lahum AAizzan", transliterationB: "Wattakhazoo min doonil laahi aalihatal liyakoonoo lahum 'izzaa", english: "And they have taken (for worship) gods other than Allah, to give them power and glory", romanUrdu: "In logon ne Allah ko chodh kar apne kuch khuda bana rakkhey hain taa-ke woh inke pushtebaan (supporters) hon" },
    { number: 82, arabic: "كَلَّا ۚ سَيَكْفُرُونَ بِعِبَادَتِهِمْ وَيَكُونُونَ عَلَيْهِمْ ضِدًّا", transliteration: "Kalla sayakfuroona biAAibadatihim wayakoonoona AAalayhim diddan", transliterationB: "Kallaa; sa yakfuroona bi'ibaadatihim wa yakoonoona 'alaihim diddaa", english: "Instead, they shall reject their worship, and become adversaries against them", romanUrdu: "Koi pushtebaan na hoga, woh sab inki ibadat ka inkar karenge aur ultey inke mukhalif ban jayenge" },
    { number: 83, arabic: "أَلَمْ تَرَ أَنَّآ أَرْسَلْنَا ٱلشَّيَٰطِينَ عَلَى ٱلْكَٰفِرِينَ تَؤُزُّهُمْ أَزًّۭا", transliteration: "Alam tara anna arsalna alshshayateena AAala alkafireena taozzuhum azzan", transliterationB: "Alam tara annaaa arsalnash Shayaateena 'alal kaafireena ta'uzzuhum azzaa", english: "Seest thou not that We have set the Evil Ones on against the unbelievers, to incite them with fury", romanUrdu: "Kya tum dekhte nahin ho ke humne in munkireen e haqq par shayateen chodh rakkhey hain jo inhein khoob khoob (mukhalifat e haqq par) uksa rahey hain" },
    { number: 84, arabic: "فَلَا تَعْجَلْ عَلَيْهِمْ ۖ إِنَّمَا نَعُدُّ لَهُمْ عَدًّۭا", transliteration: "Fala taAAjal AAalayhim innama naAAuddu lahum AAaddan", transliterationB: "Falaa ta'jal alaihim innamaa na 'uddu lahum 'addaa", english: "So make no haste against them, for We but count out to them a (limited) number (of days)", romanUrdu: "Accha, to ab inpar nuzul e azaab ke liye betaab na ho, hum inke din gin rahey hain" },
    { number: 85, arabic: "يَوْمَ نَحْشُرُ ٱلْمُتَّقِينَ إِلَى ٱلرَّحْمَٰنِ وَفْدًۭا", transliteration: "Yawma nahshuru almuttaqeena ila alrrahmani wafdan", transliterationB: "Yawma nahshurul muttaqeena ilar Rahmaani wafdaa", english: "The day We shall gather the righteous to (Allah) Most Gracious, like a band presented before a king for honours", romanUrdu: "Woh din aane wala hai jab muttaqi logon ko hum mehmaano ki tarah rehman ke huzur pesh karenge" },
    { number: 86, arabic: "وَنَسُوقُ ٱلْمُجْرِمِينَ إِلَىٰ جَهَنَّمَ وِرْدًۭا", transliteration: "Wanasooqu almujrimeena ila jahannama wirdan", transliterationB: "Wa nasooqul mujrimeena ilaa Jahannama wirdaa", english: "And We shall drive the sinners to Hell, like thirsty cattle driven down to water", romanUrdu: "Aur mujreemon ko pyase jaanwaron ki tarah jahannum ki taraf haank le jayenge" },
    { number: 87, arabic: "لَّا يَمْلِكُونَ ٱلشَّفَٰعَةَ إِلَّا مَنِ ٱتَّخَذَ عِندَ ٱلرَّحْمَٰنِ عَهْدًۭا", transliteration: "La yamlikoona alshshafaAAata illa mani ittakhatha AAinda alrrahmani AAahdan", transliterationB: "Laa yamlikoonash shafaa'ta illaa manittakhaza 'indar Rahmaani 'ahdaa", english: "None shall have the power of intercession, but such a one as has received permission (or promise) from (Allah) Most Gracious", romanUrdu: "Us waqt log koi sifarish laney par qaadir na honge bajuz uske jisne Rehman ke huzur se parwana hasil karliya ho" },
    { number: 88, arabic: "وَقَالُوا۟ ٱتَّخَذَ ٱلرَّحْمَٰنُ وَلَدًۭا", transliteration: "Waqaloo ittakhatha alrrahmanu waladan", transliterationB: "Wa qaalut takhazar Rahmaanu waladaa", english: "They say: \"(Allah) Most Gracious has begotten a son", romanUrdu: "Woh kehte hain ke rehman ne kisi ko beta bana liya hai" },
    { number: 89, arabic: "لَّقَدْ جِئْتُمْ شَيْـًٔا إِدًّۭا", transliteration: "Laqad jitum shayan iddan", transliterationB: "Laqad ji'tum shai'an iddaa", english: "Indeed ye have put forth a thing most monstrous", romanUrdu: "Sakht behuda baat hai jo tum log ghadh laye ho" },
    { number: 90, arabic: "تَكَادُ ٱلسَّمَٰوَٰتُ يَتَفَطَّرْنَ مِنْهُ وَتَنشَقُّ ٱلْأَرْضُ وَتَخِرُّ ٱلْجِبَالُ هَدًّا", transliteration: "Takadu alssamawatu yatafattarna minhu watanshaqqu alardu watakhirru aljibalu haddan", transliterationB: "Takaadus samaawaatu yatafattarna minhu wa tanshaq qul ardu wa takhirrul jibaalu haddaa", english: "At it the skies are ready to burst, the earth to split asunder, and the mountains to fall down in utter ruin", romanUrdu: "Qareeb hai ke aasmaan phatt padein, zameen shaqq ho jaye (split asunder) aur pahad gir jayein" },
    { number: 91, arabic: "أَن دَعَوْا۟ لِلرَّحْمَٰنِ وَلَدًۭا", transliteration: "An daAAaw lilrrahmani waladan", transliterationB: "An da'aw lir Rahmaani waladaa", english: "That they should invoke a son for (Allah) Most Gracious", romanUrdu: "Is baat par ke logon ne Rehman ke liye aulad honay ka dawa kiya" },
    { number: 92, arabic: "وَمَا يَنۢبَغِى لِلرَّحْمَٰنِ أَن يَتَّخِذَ وَلَدًا", transliteration: "Wama yanbaghee lilrrahmani an yattakhitha waladan", transliterationB: "Wa maa yambaghee lir Rahmaani ai yattakhiza waladaa", english: "For it is not consonant with the majesty of (Allah) Most Gracious that He should beget a son", romanUrdu: "Rehman ki yeh shaan nahin hai ke woh kisi ko beta banaye" },
    { number: 93, arabic: "إِن كُلُّ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ إِلَّآ ءَاتِى ٱلرَّحْمَٰنِ عَبْدًۭا", transliteration: "In kullu man fee alssamawati waalardi illa atee alrrahmani AAabdan", transliterationB: "In kullu man fis samaawaati wal ardi illaaa aatir Rahmaani 'abdaa", english: "Not one of the beings in the heavens and the earth but must come to (Allah) Most Gracious as a servant", romanUrdu: "Zameen aur aasmaano ke andar jo bhi hain sab uske huzoor bandon ki haisiyat se pesh honay waley hain" },
    { number: 94, arabic: "لَّقَدْ أَحْصَىٰهُمْ وَعَدَّهُمْ عَدًّۭا", transliteration: "Laqad ahsahum waAAaddahum AAaddan", transliterationB: "Laqad ahsaahum wa addahum 'addaa", english: "He does take an account of them (all), and hath numbered them (all) exactly", romanUrdu: "Sab par woh muheet (encircled) hai aur usne unko shumaar kar rakkha hai" },
    { number: 95, arabic: "وَكُلُّهُمْ ءَاتِيهِ يَوْمَ ٱلْقِيَٰمَةِ فَرْدًا", transliteration: "Wakulluhum ateehi yawma alqiyamati fardan", transliterationB: "Wa kulluhum aateehi Yawmal Qiyaamati fardaa", english: "And everyone of them will come to Him singly on the Day of Judgment", romanUrdu: "Sab qayamat ke roz fardan fardan (akele akele) uske saamne hazir hongey" },
    { number: 96, arabic: "إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ سَيَجْعَلُ لَهُمُ ٱلرَّحْمَٰنُ وُدًّۭا", transliteration: "Inna allatheena amanoo waAAamiloo alssalihati sayajAAalu lahumu alrrahmanu wuddan", transliterationB: "Innal lazeena aamanoo wa 'amilus saalihaati sa yaj'alu lahumur Rahmaanu wuddaa", english: "On those who believe and work deeds of righteousness, will (Allah) Most Gracious bestow love", romanUrdu: "Yaqeenan jo log iman le aaye hain aur amal e saleh kar rahey hain anqareeb Rehman unke liye dilon mein muhabbat paida kardega" },
    { number: 97, arabic: "فَإِنَّمَا يَسَّرْنَٰهُ بِلِسَانِكَ لِتُبَشِّرَ بِهِ ٱلْمُتَّقِينَ وَتُنذِرَ بِهِۦ قَوْمًۭا لُّدًّۭا", transliteration: "Fainnama yassarnahu bilisanika litubashshira bihi almuttaqeena watunthira bihi qawman luddan", transliterationB: "Fa innamaa yassarnaahu bilisaanika litubashshira bihil muttaqeena wa tunzira bihee qawmal luddaa", english: "So have We made the (Qur'an) easy in thine own tongue, that with it thou mayest give Glad Tidings to the righteous, and warnings to people given to contention", romanUrdu: "Pas (aey Muhammad) , is kalam ko humne aasaan karke tumhari zubaan mein isi liye nazil kiya hai ke tum parheizgaron ko khush khabri dedo aur hat-dharm (jhagdalu/obdurate) logon ko dara do" },
    { number: 98, arabic: "وَكَمْ أَهْلَكْنَا قَبْلَهُم مِّن قَرْنٍ هَلْ تُحِسُّ مِنْهُم مِّنْ أَحَدٍ أَوْ تَسْمَعُ لَهُمْ رِكْزًۢا", transliteration: "Wakam ahlakna qablahum min qarnin hal tuhissu minhum min ahadin aw tasmaAAu lahum rikzan", transliterationB: "Wa kam ahlaknaa qabla hum min qarnin hal tuhissu minhum min ahadin aw tasma'u lahum rikzaa", english: "But how many (countless) generations before them have We destroyed? Canst thou find a single one of them (now) or hear (so much as) a whisper of them", romanUrdu: "Insey pehle hum kitni hi qaumon ko halaak kar chuke hain, phir aaj kahin tum unka nishaan patey ho, ya unki bhanak bhi kahin sunayi deti hai" }
  ]
};
